package com.example.loja.models;import jakarta.persistence.*;import java.math.BigDecimal;import java.time.LocalDateTime;import java.util.ArrayList;import java.util.List;@Entity@Table(name = "orders")public class Order {    @Id    @GeneratedValue(strategy = GenerationType.AUTO)    private long id;    @ManyToOne    @JoinColumn(name = "user_id", nullable = false)    private User user;    @OneToMany(mappedBy = "order", cascade = CascadeType.ALL, orphanRemoval = true)    private List<OrderItem> items = new ArrayList<>();    private BigDecimal totalAmount;    @Enumerated(EnumType.STRING)    private OrderStatus status;    private LocalDateTime createdAt;    public Order() {        this.createdAt = LocalDateTime.now();        this.status = OrderStatus.PENDING;    }    public enum OrderStatus {        PENDING, PAID, SHIPPED, DELIVERED, CANCELED    }    public long getId() {        return id;    }    public void setId(long id) {        this.id = id;    }    public User getUser() {        return user;    }    public void setUser(User user) {        this.user = user;    }    public List<OrderItem> getItems() {        return items;    }    public void setItems(List<OrderItem> items) {        this.items = items;    }    public BigDecimal getTotalAmount() {        return totalAmount;    }    public void setTotalAmount(BigDecimal totalAmount) {        this.totalAmount = totalAmount;    }    public OrderStatus getStatus() {        return status;    }    public void setStatus(OrderStatus status) {        this.status = status;    }    public LocalDateTime getCreatedAt() {        return createdAt;    }    public void setCreatedAt(LocalDateTime createdAt) {        this.createdAt = createdAt;    }    @Override    public String toString() {        return "Order{" +                "id=" + id +                ", user=" + user +                ", items=" + items +                ", totalAmount=" + totalAmount +                ", status=" + status +                ", createdAt=" + createdAt +                '}';    }}